(window.webpackJsonp=window.webpackJsonp||[]).push([[1026],{995:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for a binary tree node.\\n * function TreeNode(val) {\\n *     this.val = val;\\n *     this.left = this.right = null;\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{TreeNode}</span> <span class=\\"hljs-variable\\">root</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{TreeNode}</span> <span class=\\"hljs-variable\\">p</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{TreeNode}</span> <span class=\\"hljs-variable\\">q</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{TreeNode}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> lowestCommonAncestor = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">root, p, q</span>) </span>{\\n  <span class=\\"hljs-keyword\\">if</span>(!root)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">null</span>\\n  <span class=\\"hljs-keyword\\">if</span>(root.val===p.val)<span class=\\"hljs-keyword\\">return</span> p\\n  <span class=\\"hljs-keyword\\">if</span>(root.val===q.val)<span class=\\"hljs-keyword\\">return</span> q\\n  <span class=\\"hljs-keyword\\">let</span> anc1=lowestCommonAncestor(root.left,p,q),\\n      anc2=lowestCommonAncestor(root.right,p,q)\\n  <span class=\\"hljs-keyword\\">if</span>(anc1!=<span class=\\"hljs-literal\\">null</span> &amp;&amp; anc2!=<span class=\\"hljs-literal\\">null</span>)<span class=\\"hljs-keyword\\">return</span> root\\n  <span class=\\"hljs-keyword\\">if</span>(anc1==<span class=\\"hljs-literal\\">null</span>)<span class=\\"hljs-keyword\\">return</span> anc2\\n  <span class=\\"hljs-keyword\\">if</span>(anc2==<span class=\\"hljs-literal\\">null</span>)<span class=\\"hljs-keyword\\">return</span> anc1   \\n};\\n</code></pre>\\n"],"titleSlug":"lowest-common-ancestor-of-a-binary-tree","hasThinking":false,"content":"<p>\u7ed9\u5b9a\u4e00\u4e2a\u4e8c\u53c9\u6811, \u627e\u5230\u8be5\u6811\u4e2d\u4e24\u4e2a\u6307\u5b9a\u8282\u70b9\u7684\u6700\u8fd1\u516c\u5171\u7956\u5148\u3002</p>\\n\\n<p><a href=\\"https://baike.baidu.com/item/%E6%9C%80%E8%BF%91%E5%85%AC%E5%85%B1%E7%A5%96%E5%85%88/8918834?fr=aladdin\\" target=\\"_blank\\">\u767e\u5ea6\u767e\u79d1</a>\u4e2d\u6700\u8fd1\u516c\u5171\u7956\u5148\u7684\u5b9a\u4e49\u4e3a\uff1a\u201c\u5bf9\u4e8e\u6709\u6839\u6811 T \u7684\u4e24\u4e2a\u8282\u70b9 p\u3001q\uff0c\u6700\u8fd1\u516c\u5171\u7956\u5148\u8868\u793a\u4e3a\u4e00\u4e2a\u8282\u70b9 x\uff0c\u6ee1\u8db3 x \u662f p\u3001q \u7684\u7956\u5148\u4e14 x \u7684\u6df1\u5ea6\u5c3d\u53ef\u80fd\u5927\uff08<strong>\u4e00\u4e2a\u8282\u70b9\u4e5f\u53ef\u4ee5\u662f\u5b83\u81ea\u5df1\u7684\u7956\u5148</strong>\uff09\u3002\u201d</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2018/12/14/binarytree.png\\" style=\\"width: 200px; height: 190px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [3,5,1,6,2,0,8,null,null,7,4], p = 5, q = 1\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n<strong>\u89e3\u91ca\uff1a</strong>\u8282\u70b9 <code>5 </code>\u548c\u8282\u70b9 <code>1 </code>\u7684\u6700\u8fd1\u516c\u5171\u7956\u5148\u662f\u8282\u70b9 <code>3 \u3002</code>\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2018/12/14/binarytree.png\\" style=\\"width: 200px; height: 190px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [3,5,1,6,2,0,8,null,null,7,4], p = 5, q = 4\\n<strong>\u8f93\u51fa\uff1a</strong>5\\n<strong>\u89e3\u91ca\uff1a</strong>\u8282\u70b9 <code>5 </code>\u548c\u8282\u70b9 <code>4 </code>\u7684\u6700\u8fd1\u516c\u5171\u7956\u5148\u662f\u8282\u70b9 <code>5 \u3002</code>\u56e0\u4e3a\u6839\u636e\u5b9a\u4e49\u6700\u8fd1\u516c\u5171\u7956\u5148\u8282\u70b9\u53ef\u4ee5\u4e3a\u8282\u70b9\u672c\u8eab\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [1,2], p = 1, q = 2\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u6811\u4e2d\u8282\u70b9\u6570\u76ee\u5728\u8303\u56f4 <code>[2, 10<sup>5</sup>]</code> \u5185\u3002</li>\\n\\t<li><code>-10<sup>9</sup> <= Node.val <= 10<sup>9</sup></code></li>\\n\\t<li>\u6240\u6709 <code>Node.val</code> <code>\u4e92\u4e0d\u76f8\u540c</code> \u3002</li>\\n\\t<li><code>p != q</code></li>\\n\\t<li><code>p</code> \u548c <code>q</code> \u5747\u5b58\u5728\u4e8e\u7ed9\u5b9a\u7684\u4e8c\u53c9\u6811\u4e2d\u3002</li>\\n</ul>\\n","title":"236. \u4e8c\u53c9\u6811\u7684\u6700\u8fd1\u516c\u5171\u7956\u5148","relatedTags":["\u6811"],"difficult":"Middle","lang":["javascript"],"uniqueID":"236"}')}}]);